import {
  LOGIN_SUCCESS,
  LOGIN_ERROR,
  REGISTER_ERROR,
  SET_USER,
  LOGOUT
} from './authTypes';

const initialState = {
  isAuth: false,
  loading: true,
  user: null,
  loginError: null,
  registerError: null
};

export default function authReducer(state = initialState, action) {
  switch (action.type) {

    case LOGIN_SUCCESS:
      return {
        ...state,
        isAuth: true,
		loading: false,
        user: action.payload,
        loginError: null,
		registerError: null
      };

    case SET_USER:
      return {
        ...state,
        isAuth: true,
		loading: false,
        user: action.payload,
        loginError: null,
		registerError: null
      };

    case LOGIN_ERROR:
      return {
        ...state,
        isAuth: false,
		loading: false,
        user: null,
		loginError: action.payload,
		registerError: null
      };
	  
	case REGISTER_ERROR:
      return {
        ...state,
        isAuth: false,
		loading: false,
        user: null,
		loginError: null,
		registerError: action.payload
      };

    case LOGOUT:
      return initialState;

    default:
      return state;
  }
}
